/* exp(x), x < 2^-16, two fraction limbs.  N = 7 terms: the dropped
   x^8/8! is about 2^-143, below the 2^-128 output ulp.

   R = C4 + x (C5 + x (C6 + x C7)) needs only 58 bits, so it and the
   two Horner steps below it run at a single limb, on x's top limb
   alone; Q = C3 + x R and P = C2 + x Q then need two. */
static void
_fixed_exp_series_2(nn_ptr res, nn_srcptr x)
{
    ulong X1 = x[1], X0 = x[0];
    ulong u, s, r, q1, q0, p1, p0, h, l, x2h, x2l;

    /* inner tail at one limb */
    u = FIXED_EXP_E6 + n_mulhi(X1, FIXED_EXP_E7);
    s = FIXED_EXP_E5 + n_mulhi(X1, u);
    r = FIXED_EXP_E4 + n_mulhi(X1, s);

    /* Q = C3 + x R (R is a single limb) */
    _fixed_mulhi_2x1(&h, &l, X1, X0, r);
    add_ssaaaa(q1, q0, FIXED_EXP_D3_HI, FIXED_EXP_D3_LO, h, l);

    /* P = C2 + x Q */
    _fixed_mulhi_2x2_sloppy(&h, &l, X1, X0, q1, q0);
    add_ssaaaa(p1, p0, FIXED_EXP_D2_HI, FIXED_EXP_D2_LO, h, l);

    /* x^2 P, then the fraction x + x^2 P */
    _fixed_sqrhi_2x2(&x2h, &x2l, X1, X0);
    _fixed_mulhi_2x2_sloppy(&h, &l, x2h, x2l, p1, p0);
    add_ssaaaa(h, l, h, l, X1, X0);

    res[0] = l;
    res[1] = h;
    res[2] = 1;
}
void
fixed_exp_opt_2(nn_ptr res, nn_srcptr x)
{
    const int r = 16;
    slong i, j, num, bj, nc;
    ulong t0, t1, bw, h, e;
    ulong d0, d1;
    ulong y0, y1, y2;
    ulong s0, s1, s2;
    ulong ts[2], ys[4], sh[3];
    slong used[2 * FLINT_BITS + 2];


    nn_srcptr tab;
    tab = _fixed_exp_logs_tab(2, r, &nc);

    t0 = x[0];
    t1 = x[1];

/* exact compare-subtract of L_ii, recording the index */
#define STEP(ii) \
    do { \
        nn_srcptr Lq = tab + (ii) * nc + (nc - 2); \
        sub_dddmmmsss(bw, d1, d0, \
            UWORD(0), t1, t0, \
            UWORD(0), Lq[1], Lq[0]); \
        t0 = (t0 & bw) | (d0 & ~bw); \
        t1 = (t1 & bw) | (d1 & ~bw); \
        used[num] = (ii); \
        num += (bw == 0); \
    } while (0)

/* apply the pending recorded subtractions */
#define FLUSH() \
    for (; bj < num; bj++) \
    { \
        nn_srcptr Lq = tab + used[bj] * nc + (nc - 2); \
        sub_ddmmss(t1, t0, \
            t1, t0, \
            Lq[1], Lq[0]); \
    }

    num = 0;
    bj = 0;

    for (i = 0; i <= r; i++)
        STEP(i);
    bj = num;
    (void) h; (void) e;

    FLUSH();

    /* one extra subtraction restores t < L_r < 2^-r */
    STEP(r);

#undef STEP
#undef FLUSH

    /* exp of the reduced argument */
    ts[0] = t0;
    ts[1] = t1;
    _fixed_exp_series_2(ys, ts);
    y0 = ys[0];
    y1 = ys[1];
    y2 = ys[2];

    j = 0;

    if (num > 0 && used[0] == 0)
    {
        add_sssaaaaaa(y2, y1, y0,
            y2, y1, y0, y2, y1, y0);
        j = 1;
    }

    for (; j < num && used[j] < FLINT_BITS; j++)
    {
        int b = (int) used[j];

        s0 = MPN_RIGHT_SHIFT_LOW(y1, y0, b);
        s1 = MPN_RIGHT_SHIFT_LOW(y2, y1, b);
        s2 = y2 >> b;
        add_sssaaaaaa(y2, y1, y0,
            y2, y1, y0, s2, s1, s0);
    }

    ys[0] = y0;
    ys[1] = y1;
    ys[2] = y2;

    /* rare factors with i >= FLINT_BITS */
    if (j < num)
        _fixed_exp_recon(ys, sh, 3, used, j, num);

    res[0] = ys[0];
    res[1] = ys[1];
    res[2] = ys[2];
}


